// newLearnConfig returns the per-CLI entity extractor Config the
// teach / recall / normalize call sites pass into the learn package.
// Registers ESPN's ticker shapes (event IDs, athlete IDs, team URL
// identifiers) plus sports vocabulary the entity extractor should
// drop before token-matching.
func newLearnConfig() *entities.Config {
	cfg := entities.NewConfig()
	for _, pat := range []string{
		`^[0-9]{9}$`,          // ESPN event IDs (game IDs)
		`^a-[0-9]+$`,          // ESPN athlete IDs (URL-style)
		`^[a-z]{2,4}-[a-z]+$`, // ESPN team URL identifiers (e.g., "sf-49ers")
	} {
		re, err := regexp.Compile(pat)
		if err != nil {
			fmt.Fprintf(os.Stderr, "warning: espn-pp-cli: ticker pattern %q failed to compile: %v\n", pat, err)
			continue
		}
		cfg.RegisterTickerPattern(re)
	}
	cfg.RegisterStopwords(
		"vs", "v", "versus",
		"game", "games", "match", "matches",
		"tonight", "today", "yesterday", "tomorrow", "weekend",
		"schedule", "scoreboard", "score", "scores",
		"result", "results", "winner",
		"stats", "standings", "lineup", "roster",
		// League names treated as stopwords so caps ("NBA") and
		// lowercase ("nba") collapse to the same family key. Without
		// this, the entity extractor's ALL-CAPS rule promotes "NBA"
		// to entity, stripping it from the family while lowercase
		// "nba" stays as content. Different families = different
		// recall hits for the same intent.
		"mlb", "nba", "nfl", "nhl", "mls",
	)
	return cfg
}

